    pthread_mutex_lock(&mutex1);
    pthread_mutex_lock(&mutex2);
    // work
    pthread_mutex_unlock(&mutex1);  // Noncompliant: inconsistent order
    pthread_mutex_unlock(&mutex2);
}

compliant:
// Consistent LIFO (Last In, First Out) mutex unlock order
pthread_mutex_t mutex1 = PTHREAD_MUTEX_INITIALIZER;
pthread_mutex_t mutex2 = PTHREAD_MUTEX_INITIALIZER;
pthread_mutex_t mutex3 = PTHREAD_MUTEX_INITIALIZER;

void transfer_funds() {
    pthread_mutex_lock(&mutex1);    // Lock order: 1, 2, 3
    pthread_mutex_lock(&mutex2);
    pthread_mutex_lock(&mutex3);

    // Do work

    pthread_mutex_unlock(&mutex3);  // Compliant: unlock in reverse order
    pthread_mutex_unlock(&mutex2);  // (LIFO: 3, 2, 1)
    pthread_mutex_unlock(&mutex1);
}

// Consistent ordering across all functions
void function_a() {
    pthread_mutex_lock(&mutex1);
    pthread_mutex_lock(&mutex2);
    // work
    pthread_mutex_unlock(&mutex2);  // Compliant: reverse order
    pthread_mutex_unlock(&mutex1);
}

void function_b() {
    pthread_mutex_lock(&mutex1);
    pthread_mutex_lock(&mutex2);
    // work
    pthread_mutex_unlock(&mutex2);  // Compliant: same reverse order
    pthread_mutex_unlock(&mutex1);
}
